483→/**
484→ * Polls for an observation linked to a given entity via the observes edge.
485→ * Returns when at least one observation is found, or throws on timeout.
486→ */
487→export async function waitForObservation(
488→  surreal: Surreal,
489→  entityTable: string,
490→  entityId: string,
491→  timeoutMs = 15_000,
492→): Promise<ObservationRecord[]> {
493→  const start = Date.now();
494→
495→  while (Date.now() - start < timeoutMs) {
496→    const observations = await getObservationsForEntity(surreal, entityTable, entityId);
497→    if (observations.length > 0) {
498→      return observations;
499→    }
500→    await Bun.sleep(250);
501→  }
502→
503→  throw new Error(
504→    `No observation found for ${entityTable}:${entityId} within ${timeoutMs}ms`,
505→  );
506→}
