508→/**
509→ * Queries all observations linked to an entity via the observes edge.
510→ */
511→export async function getObservationsForEntity(
512→  surreal: Surreal,
513→  entityTable: string,
514→  entityId: string,
515→): Promise<ObservationRecord[]> {
516→  const entityRecord = new RecordId(entityTable, entityId);
517→
518→  // Query via reverse traversal from the entity through observes edges
519→  const reverseRows = (await surreal.query(
520→    `SELECT <-observes<-observation AS obs FROM $entity;`,
521→    { entity: entityRecord },
522→  )) as Array<Array<{ obs: RecordId[] }>>;
523→
524→  const obsIds = reverseRows[0]?.[0]?.obs ?? [];
525→  if (obsIds.length === 0) return [];
526→
527→  const allObs = (await surreal.query(
528→    `SELECT * FROM observation WHERE id IN $ids;`,
529→    { ids: obsIds },
530→  )) as Array<ObservationRecord[]>;
531→
532→  return allObs[0] ?? [];
533→}
