610→/**
611→ * Creates a test workspace and identity for observer tests.
612→ * Returns workspace ID, identity ID, and the test user.
613→ */
614→export async function setupObserverWorkspace(
615→  baseUrl: string,
616→  surreal: Surreal,
617→  suffix: string,
618→): Promise<{
619→  user: TestUser;
620→  workspaceId: string;
621→  identityId: string;
622→}> {
623→  const { createTestUser, createTestWorkspace } = await import(
624→    "../coding-agent-orchestrator/orchestrator-test-kit"
625→  );
626→
627→  const user = await createTestUser(baseUrl, suffix);
628→  const workspace = await createTestWorkspace(baseUrl, user);
629→
630→  // Create an agent identity in this workspace
631→  const identityId = `id-${crypto.randomUUID()}`;
632→  const identityRecord = new RecordId("identity", identityId);
633→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
634→
635→  await surreal.query(`CREATE $identity CONTENT $content;`, {
636→    identity: identityRecord,
637→    content: {
638→      name: `Observer Test Agent ${suffix}`,
639→      type: "agent",
640→      identity_status: "active",
641→      workspace: workspaceRecord,
642→      created_at: new Date(),
643→    },
644→  });
645→
646→  return { user, workspaceId: workspace.workspaceId, identityId };
647→}
